onClick:
{{
Promise.all([

    ObtenerFCImpresionConsulta.run(),
    ObtenerDetalleFCImpConsulta.run()

])

.then(async () => {

    await storeValue(
        "fcImpresion",
        ObtenerFCImpresionConsulta.data[0]
    );

    await storeValue(
        "detalleFCImpresion",
        ObtenerDetalleFCImpConsulta.data
    );

    download(
        JS_ImpresionFC.generarHTMLFC(),
        "FC-" +
        String(
            ObtenerFCImpresionConsulta.data[0].id_factura_compra
        ).padStart(6, "0")
        +
        ".html",
        "text/html"
    );

    showAlert(
        "Factura descargada correctamente",
        "success"
    );

});
}}

tooltip:
{{
!tblFCConsulta.selectedRow?.id_factura_compra
?
"Debe seleccionar una factura en la tabla"
:
""
}}
